{"metadata":{"kernelspec":{"language":"python","display_name":"Python 3","name":"python3"},"language_info":{"name":"python","version":"3.12.13","mimetype":"text/x-python","codemirror_mode":{"name":"ipython","version":3},"pygments_lexer":"ipython3","nbconvert_exporter":"python","file_extension":".py"},"kaggle":{"accelerator":"none","dataSources":[{"sourceType":"datasetVersion","sourceId":1207035}],"isInternetEnabled":false,"language":"python","sourceType":"notebook","isGpuEnabled":false}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"code","source":"import pandas as pd\nimport joblib\n\n# Load Files\nmodel = joblib.load(\"logistic_regression.pkl\")\nscaler = joblib.load(\"scaler.pkl\")\nencoders = joblib.load(\"label_encoders.pkl\")\n\n# Load Sample\ndf = pd.read_csv(\"/kaggle/input/datasets/laotse/credit-risk-dataset/credit_risk_dataset.csv\")\n\nsample = df.drop(\"loan_status\", axis=1).iloc[[0]].copy()\n\n# Encode Categorical Features\ncategorical_columns = [\n    \"person_home_ownership\",\n    \"loan_intent\",\n    \"loan_grade\",\n    \"cb_person_default_on_file\"\n]\n\nfor col in categorical_columns:\n    sample[col] = encoders[col].transform(sample[col])\n\n# Scale\nsample = scaler.transform(sample)\n\n# Predict\nprediction = model.predict(sample)[0]\nprobability = model.predict_proba(sample)[0][1]\n\nprint(\"=\" * 40)\n\nif prediction == 1:\n    print(\"⚠️ High Credit Risk\")\nelse:\n    print(\"✅ Low Credit Risk\")\n\nprint(f\"Risk Probability: {probability:.2%}\")","metadata":{"_uuid":"8f2839f25d086af736a60e9eeb907d3b93b6e0e5","_cell_guid":"b1076dfc-b9ad-4769-8c92-a6c4dae69d19","trusted":true,"execution":{"iopub.status.busy":"2026-07-19T10:41:32.706423Z","iopub.execute_input":"2026-07-19T10:41:32.70683Z","iopub.status.idle":"2026-07-19T10:41:32.779001Z","shell.execute_reply.started":"2026-07-19T10:41:32.706797Z","shell.execute_reply":"2026-07-19T10:41:32.777853Z"}},"outputs":[{"name":"stdout","text":"========================================\n⚠️ High Credit Risk\nRisk Probability: 80.52%\n","output_type":"stream"}],"execution_count":9}]}